external_knowledge:
- 'gender_id = 0' refers to male gender;
- 'source_id = 1' indicates the primary data source;
- 'frequency' represents how often the name was given during a specified decade.

sql:
SELECT comment_text
FROM name_comments
WHERE name_id = 0;

SELECT baby_names.name, decades.start_year AS birth_year
FROM baby_names
INNER JOIN decades ON baby_names.decade_id = decades.decade_id;

SELECT name 
FROM name_submissions 
WHERE user_id = 0;

SELECT name
FROM baby_names
WHERE frequency > (SELECT AVG(frequency) FROM baby_names);
